import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  FaDownload, FaEye, FaBook, FaFilePdf, FaFileAlt, 
  FaQuestionCircle, FaHistory, FaArrowLeft, FaBookOpen, 
  FaClock, FaStar, FaSpinner, FaUser, FaSearch,
  FaFilter, FaFileWord, FaFilePowerpoint, FaFileImage,
  FaFileArchive, FaPrint
} from 'react-icons/fa';
import { coursesData, getSubjects } from '../data/coursesData'; // Import your courses data

const MaterialsPage = () => {
  const { courseId, yearId, semId, subjectId } = useParams();
  const navigate = useNavigate();
  
  const [subject, setSubject] = useState(null);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedType, setSelectedType] = useState('all');
  const [downloading, setDownloading] = useState({});
  const [searchQuery, setSearchQuery] = useState('');
  const [courseInfo, setCourseInfo] = useState(null);

  // Material types
  const materialTypes = [
    { id: 'all', name: 'All Materials', icon: <FaFilter />, color: '#6b7280' },
    { id: 'syllabus', name: 'Syllabus', icon: <FaBook />, color: '#3B82F6' },
    { id: 'notes', name: 'Notes', icon: <FaFileAlt />, color: '#10B981' },
    { id: 'pyq', name: 'PYQs', icon: <FaHistory />, color: '#8B5CF6' },
    { id: 'important', name: 'Imp Questions', icon: <FaQuestionCircle />, color: '#F59E0B' },
    { id: 'lab', name: 'Lab Manuals', icon: <FaBookOpen />, color: '#EF4444' },
    { id: 'assignment', name: 'Assignments', icon: <FaFilePdf />, color: '#EC4899' }
  ];

  // Get file icon
  const getFileIcon = (fileType) => {
    const type = fileType?.toLowerCase() || 'pdf';
    if (type.includes('pdf')) return <FaFilePdf style={{ color: '#ef4444' }} />;
    if (type.includes('doc')) return <FaFileWord style={{ color: '#2563eb' }} />;
    if (type.includes('ppt')) return <FaFilePowerpoint style={{ color: '#f97316' }} />;
    if (type.includes('jpg') || type.includes('png')) return <FaFileImage style={{ color: '#10b981' }} />;
    if (type.includes('zip')) return <FaFileArchive style={{ color: '#8b5cf6' }} />;
    return <FaFileAlt style={{ color: '#6b7280' }} />;
  };

  // Fetch subject data from your coursesData
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      
      try {
        // Get all subjects for this semester
        const subjects = getSubjects(parseInt(courseId), parseInt(yearId), parseInt(semId));
        
        // Find the specific subject by ID
        const foundSubject = subjects.find(sub => sub.id === parseInt(subjectId));
        
        if (foundSubject) {
          setSubject(foundSubject);
          
          // Get course info
          const course = coursesData[courseId];
          setCourseInfo(course);
          
          // Generate mock materials for this subject
          const mockMaterials = generateMockMaterials(foundSubject);
          setMaterials(mockMaterials);
        } else {
          console.error('Subject not found:', { courseId, yearId, semId, subjectId });
          // Fallback
          setSubject({
            id: parseInt(subjectId),
            name: 'Subject Not Found',
            code: 'N/A',
            credits: 0,
            materials: 0,
            rating: 0
          });
          setMaterials([]);
        }
      } catch (error) {
        console.error('Error loading data:', error);
      } finally {
        setLoading(false);
      }
    };
    
    loadData();
  }, [courseId, yearId, semId, subjectId]);

  // Generate mock materials based on subject
  const generateMockMaterials = (subjectData) => {
    const baseMaterials = [
      {
        id: 1,
        title: `${subjectData.name} Complete Syllabus`,
        type: 'syllabus',
        description: `Official syllabus for ${subjectData.name} with unit-wise distribution and marking scheme`,
        fileSize: '1.2 MB',
        pages: 12,
        uploadDate: '15 Jan 2024',
        downloads: subjectData.materials * 10 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 20 + Math.floor(Math.random() * 100),
        rating: subjectData.rating,
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Admin',
        isNew: true
      },
      {
        id: 2,
        title: `${subjectData.name} Complete Notes`,
        type: 'notes',
        description: `Comprehensive notes covering all topics of ${subjectData.name} with examples`,
        fileSize: '4.5 MB',
        pages: 45,
        uploadDate: '20 Jan 2024',
        downloads: subjectData.materials * 15 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 30 + Math.floor(Math.random() * 100),
        rating: subjectData.rating + 0.3,
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Professor',
        isNew: true
      },
      {
        id: 3,
        title: `${subjectData.name} PYQ 2020-2023`,
        type: 'pyq',
        description: `Previous year question papers with solutions for ${subjectData.name}`,
        fileSize: '3.2 MB',
        pages: 35,
        uploadDate: '05 Jan 2024',
        downloads: subjectData.materials * 20 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 40 + Math.floor(Math.random() * 100),
        rating: subjectData.rating + 0.4,
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Exam Cell'
      },
      {
        id: 4,
        title: `${subjectData.name} Important Questions`,
        type: 'important',
        description: `Most expected questions and important topics for ${subjectData.name} exams`,
        fileSize: '1.5 MB',
        pages: 18,
        uploadDate: '22 Jan 2024',
        downloads: subjectData.materials * 12 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 25 + Math.floor(Math.random() * 100),
        rating: subjectData.rating + 0.1,
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Faculty'
      }
    ];

    // Add lab manual for lab subjects
    if (subjectData.type === 'Lab') {
      baseMaterials.push({
        id: 5,
        title: `${subjectData.name} Lab Manual`,
        type: 'lab',
        description: `Complete lab manual with experiments, procedures, and viva questions`,
        fileSize: '2.8 MB',
        pages: 32,
        uploadDate: '18 Jan 2024',
        downloads: subjectData.materials * 8 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 18 + Math.floor(Math.random() * 100),
        rating: subjectData.rating + 0.2,
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Lab Incharge'
      });
    }

    // Add assignment for theory subjects
    if (subjectData.type === 'Theory') {
      baseMaterials.push({
        id: 6,
        title: `${subjectData.name} Assignments`,
        type: 'assignment',
        description: `Solved assignments and practice problems for ${subjectData.name}`,
        fileSize: '2.1 MB',
        pages: 25,
        uploadDate: '25 Jan 2024',
        downloads: subjectData.materials * 9 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 22 + Math.floor(Math.random() * 100),
        rating: subjectData.rating + 0.1,
        fileUrl: '#',
        fileType: 'doc',
        user: 'Teaching Assistant'
      });
    }

    return baseMaterials;
  };

  // Handle back
  const handleBack = () => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semId}`);
  };

  // Handle download
  const handleDownload = (material) => {
    setDownloading(prev => ({ ...prev, [material.id]: true }));
    
    setTimeout(() => {
      alert(`✅ Downloaded: ${material.title}`);
      setDownloading(prev => ({ ...prev, [material.id]: false }));
      
      // Update download count
      setMaterials(prev =>
        prev.map(m =>
          m.id === material.id
            ? { ...m, downloads: m.downloads + 1 }
            : m
        )
      );
    }, 1000);
  };

  // Handle preview
  const handlePreview = (material) => {
    alert(`📄 Preview: ${material.title}\n\n${material.description}\n\nFile Type: ${material.fileType.toUpperCase()}\nFile Size: ${material.fileSize}\nPages: ${material.pages}`);
  };

  // Filter materials
  const filteredMaterials = materials.filter(material => {
    const matchesType = selectedType === 'all' || material.type === selectedType;
    const matchesSearch = searchQuery === '' ||
      material.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      material.description.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesType && matchesSearch;
  });

  // Calculate stats
  const getMaterialStats = () => {
    const stats = {};
    materialTypes.forEach(type => {
      if (type.id !== 'all') {
        stats[type.id] = materials.filter(m => m.type === type.id).length;
      }
    });
    return stats;
  };

  const materialStats = getMaterialStats();

  // Styles
  const styles = {
    container: {
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)',
      padding: '20px',
      fontFamily: '"Segoe UI", Tahoma, Geneva, Verdana, sans-serif'
    },
    innerContainer: {
      maxWidth: '1200px',
      margin: '0 auto'
    },
    backButton: {
      display: 'inline-flex',
      alignItems: 'center',
      gap: '8px',
      padding: '12px 24px',
      background: '#4f46e5',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '16px',
      marginBottom: '30px',
      boxShadow: '0 4px 6px rgba(79, 70, 229, 0.2)',
      transition: 'all 0.3s ease'
    },
    subjectHeader: {
      background: 'white',
      padding: '30px',
      borderRadius: '16px',
      marginBottom: '30px',
      boxShadow: '0 10px 25px rgba(0, 0, 0, 0.1)',
      display: 'flex',
      alignItems: 'center',
      gap: '25px'
    },
    subjectIconContainer: {
      width: '90px',
      height: '90px',
      borderRadius: '50%',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      flexShrink: '0'
    },
    subjectIcon: {
      fontSize: '40px',
      color: 'white'
    },
    subjectInfo: {
      flex: '1'
    },
    subjectName: {
      fontSize: '32px',
      fontWeight: '700',
      color: '#1f2937',
      marginBottom: '10px'
    },
    subjectCode: {
      fontSize: '18px',
      color: '#6b7280',
      marginBottom: '15px',
      display: 'flex',
      alignItems: 'center',
      gap: '20px'
    },
    breadcrumb: {
      display: 'flex',
      alignItems: 'center',
      gap: '10px',
      fontSize: '14px',
      color: '#9ca3af',
      flexWrap: 'wrap'
    },
    breadcrumbItem: {
      padding: '6px 12px',
      background: '#f3f4f6',
      borderRadius: '6px'
    },
    currentBreadcrumb: {
      background: '#4f46e5',
      color: 'white'
    },
    statsBox: {
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      padding: '20px',
      borderRadius: '12px',
      color: 'white',
      textAlign: 'center',
      minWidth: '120px'
    },
    statsNumber: {
      fontSize: '32px',
      fontWeight: '700',
      marginBottom: '5px'
    },
    statsLabel: {
      fontSize: '14px',
      opacity: '0.9'
    }
  };

  if (loading) {
    return (
      <div style={styles.container}>
        <div style={styles.innerContainer}>
          <div style={{ textAlign: 'center', padding: '100px' }}>
            <div style={{
              width: '50px',
              height: '50px',
              border: '5px solid #f3f4f6',
              borderTop: '5px solid #4f46e5',
              borderRadius: '50%',
              margin: '0 auto 20px',
              animation: 'spin 1s linear infinite'
            }}></div>
            <h3 style={{ color: '#6b7280' }}>Loading Subject...</h3>
          </div>
        </div>
      </div>
    );
  }

  if (!subject) {
    return (
      <div style={styles.container}>
        <div style={styles.innerContainer}>
          <button style={styles.backButton} onClick={() => navigate(-1)}>
            <FaArrowLeft /> Back
          </button>
          <div style={{ textAlign: 'center', padding: '100px' }}>
            <h2>Subject not found</h2>
            <p>The requested subject could not be found.</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
      
      <div style={styles.innerContainer}>
        
        {/* Back Button */}
        <button style={styles.backButton} onClick={handleBack}>
          <FaArrowLeft /> Back to Subjects
        </button>
        
        {/* Subject Header */}
        <div style={styles.subjectHeader}>
          <div style={styles.subjectIconContainer}>
            <div style={styles.subjectIcon}>📚</div>
          </div>
          
          <div style={styles.subjectInfo}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
              <div>
                <h1 style={styles.subjectName}>{subject.name}</h1>
                <div style={styles.subjectCode}>
                  <span>Code: <strong>{subject.code}</strong></span>
                  <span>⭐ <strong>{subject.credits} Credits</strong></span>
                  <span>📁 <strong>{subject.materials} Materials</strong></span>
                  <span>🏷️ <strong>{subject.type}</strong></span>
                </div>
                
                <div style={styles.breadcrumb}>
                  <span style={styles.breadcrumbItem}>
                    {courseInfo?.name || `Course ${courseId}`}
                  </span>
                  <span>→</span>
                  <span style={styles.breadcrumbItem}>
                    Year {yearId}
                  </span>
                  <span>→</span>
                  <span style={styles.breadcrumbItem}>
                    Semester {semId}
                  </span>
                  <span>→</span>
                  <span style={{ ...styles.breadcrumbItem, ...styles.currentBreadcrumb }}>
                    {subject.name}
                  </span>
                </div>
              </div>
              
              <div style={styles.statsBox}>
                <div style={styles.statsNumber}>{materials.length}</div>
                <div style={styles.statsLabel}>Total Files</div>
                <div style={{ ...styles.statsLabel, fontSize: '12px', marginTop: '5px' }}>
                  {subject.materials} Available
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Rest of your Materials Grid Code Here */}
        {/* You can keep the same materials grid UI from earlier */}
        {/* Just update it to use filteredMaterials */}
        
        {/* Search Bar */}
        <div style={{
          background: 'white',
          padding: '20px',
          borderRadius: '12px',
          marginBottom: '25px',
          boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
        }}>
          <div style={{ position: 'relative' }}>
            <input
              type="text"
              placeholder={`Search ${subject.name} materials...`}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              style={{
                width: '100%',
                padding: '16px 20px 16px 50px',
                fontSize: '16px',
                border: '2px solid #e5e7eb',
                borderRadius: '10px',
                background: '#f9fafb',
                transition: 'all 0.3s'
              }}
            />
            <div style={{
              position: 'absolute',
              left: '20px',
              top: '50%',
              transform: 'translateY(-50%)',
              color: '#9ca3af',
              fontSize: '18px'
            }}>
              <FaSearch />
            </div>
            {searchQuery && (
              <button
                style={{
                  position: 'absolute',
                  right: '20px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: '#9ca3af',
                  cursor: 'pointer',
                  fontSize: '18px'
                }}
                onClick={() => setSearchQuery('')}
              >
                ✕
              </button>
            )}
          </div>
        </div>

        {/* Filter Buttons */}
        <div style={{
          background: 'white',
          padding: '20px',
          borderRadius: '12px',
          marginBottom: '25px',
          boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
        }}>
          <h3 style={{
            fontSize: '20px',
            fontWeight: '600',
            color: '#1f2937',
            marginBottom: '15px'
          }}>
            Filter by Material Type
          </h3>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
            {materialTypes.map((type) => (
              <button
                key={type.id}
                onClick={() => setSelectedType(type.id)}
                style={{
                  padding: '12px 20px',
                  border: `2px solid ${selectedType === type.id ? type.color : '#e5e7eb'}`,
                  borderRadius: '8px',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                  fontSize: '14px',
                  fontWeight: '500',
                  background: selectedType === type.id ? `${type.color}15` : 'white',
                  color: selectedType === type.id ? type.color : '#4b5563',
                  transition: 'all 0.3s'
                }}
              >
                {type.icon}
                {type.name}
                {type.id !== 'all' && (
                  <span style={{
                    background: '#f3f4f6',
                    color: '#6b7280',
                    padding: '2px 8px',
                    borderRadius: '12px',
                    fontSize: '12px',
                    fontWeight: 'bold'
                  }}>
                    {materialStats[type.id] || 0}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Materials Grid */}
        {filteredMaterials.length === 0 ? (
          <div style={{
            background: 'white',
            padding: '60px 20px',
            borderRadius: '12px',
            textAlign: 'center',
            boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
          }}>
            <div style={{ fontSize: '60px', marginBottom: '20px', opacity: '0.5' }}>📭</div>
            <h3 style={{ fontSize: '24px', fontWeight: '600', color: '#6b7280', marginBottom: '10px' }}>
              No materials found
            </h3>
            <p style={{ color: '#9ca3af', fontSize: '16px', marginBottom: '30px' }}>
              {searchQuery 
                ? `No materials match "${searchQuery}"`
                : 'No materials available for this subject'
              }
            </p>
            {searchQuery && (
              <button
                style={{
                  padding: '12px 30px',
                  background: '#4f46e5',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontWeight: '600',
                  fontSize: '16px'
                }}
                onClick={() => setSearchQuery('')}
              >
                Clear Search
              </button>
            )}
          </div>
        ) : (
          <div style={{
            background: 'white',
            padding: '30px',
            borderRadius: '12px',
            boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
              <h3 style={{ fontSize: '24px', fontWeight: '700', color: '#1f2937' }}>
                {selectedType === 'all' ? 'All Study Materials' : materialTypes.find(t => t.id === selectedType)?.name}
              </h3>
              <span style={{ color: '#6b7280' }}>
                {filteredMaterials.length} material{filteredMaterials.length !== 1 ? 's' : ''}
              </span>
            </div>
            
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))',
              gap: '25px'
            }}>
              {filteredMaterials.map((material) => {
                const typeInfo = materialTypes.find(t => t.id === material.type);
                
                return (
                  <div
                    key={material.id}
                    style={{
                      border: '1px solid #e5e7eb',
                      borderRadius: '12px',
                      overflow: 'hidden',
                      transition: 'all 0.4s ease',
                      background: 'white'
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.transform = 'translateY(-5px)';
                      e.currentTarget.style.boxShadow = '0 20px 40px rgba(0, 0, 0, 0.1)';
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.transform = 'none';
                      e.currentTarget.style.boxShadow = 'none';
                    }}
                  >
                    {/* Header */}
                    <div style={{
                      padding: '18px',
                      display: 'flex',
                      justifyContent: 'space-between',
                      alignItems: 'center',
                      borderBottom: '1px solid #e5e7eb',
                      background: `${typeInfo?.color}10`
                    }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span style={{ color: typeInfo?.color }}>
                          {typeInfo?.icon}
                        </span>
                        <span style={{ color: typeInfo?.color, fontWeight: '600' }}>
                          {typeInfo?.name}
                        </span>
                      </div>
                      
                      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '5px', color: '#6b7280', fontSize: '14px' }}>
                          <FaUser size={12} /> {material.user}
                        </div>
                        {material.isNew && (
                          <span style={{
                            background: '#ef4444',
                            color: 'white',
                            padding: '4px 12px',
                            borderRadius: '20px',
                            fontSize: '12px',
                            fontWeight: 'bold'
                          }}>
                            NEW
                          </span>
                        )}
                      </div>
                    </div>
                    
                    {/* Content */}
                    <div style={{ padding: '25px' }}>
                      <h4 style={{
                        fontSize: '20px',
                        fontWeight: '600',
                        color: '#1f2937',
                        marginBottom: '12px',
                        lineHeight: '1.4'
                      }}>
                        {material.title}
                      </h4>
                      <p style={{
                        color: '#6b7280',
                        fontSize: '15px',
                        lineHeight: '1.6',
                        marginBottom: '20px'
                      }}>
                        {material.description}
                      </p>
                      
                      <div style={{
                        display: 'grid',
                        gridTemplateColumns: '1fr 1fr',
                        gap: '15px',
                        marginBottom: '20px'
                      }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '14px' }}>
                          <FaClock color="#9ca3af" size={14} />
                          <span>{material.uploadDate}</span>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '14px' }}>
                          <FaDownload color="#9ca3af" size={14} />
                          <span>{material.downloads} downloads</span>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '14px' }}>
                          <FaEye color="#9ca3af" size={14} />
                          <span>{material.views} views</span>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '14px' }}>
                          <FaStar color="#fbbf24" size={14} />
                          <span>{material.rating}/5 rating</span>
                        </div>
                      </div>
                      
                      <div style={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        paddingTop: '15px',
                        borderTop: '1px solid #e5e7eb',
                        fontSize: '13px',
                        color: '#9ca3af'
                      }}>
                        <span style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                          {getFileIcon(material.fileType)}
                          <span>{material.fileSize}</span>
                        </span>
                        <span>📖 {material.pages} pages</span>
                      </div>
                    </div>
                    
                    {/* Action Buttons */}
                    <div style={{
                      padding: '20px',
                      background: '#f9fafb',
                      borderTop: '1px solid #e5e7eb',
                      display: 'flex',
                      gap: '12px'
                    }}>
                      <button
                        style={{
                          flex: '1',
                          padding: '14px',
                          background: 'white',
                          border: '2px solid #e5e7eb',
                          borderRadius: '8px',
                          cursor: 'pointer',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          gap: '10px',
                          fontWeight: '600',
                          color: '#4b5563',
                          transition: 'all 0.3s'
                        }}
                        onClick={() => handlePreview(material)}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.background = '#f3f4f6';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.background = 'white';
                        }}
                      >
                        <FaEye /> Preview
                      </button>
                      
                      <button
                        style={{
                          flex: '2',
                          padding: '14px',
                          background: 'linear-gradient(135deg, #10b981 0%, #34d399 100%)',
                          color: 'white',
                          border: 'none',
                          borderRadius: '8px',
                          cursor: 'pointer',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          gap: '10px',
                          fontWeight: '600',
                          fontSize: '16px',
                          transition: 'all 0.3s'
                        }}
                        onClick={() => handleDownload(material)}
                        disabled={downloading[material.id]}
                        onMouseEnter={(e) => {
                          if (!downloading[material.id]) {
                            e.currentTarget.style.background = 'linear-gradient(135deg, #059669 0%, #10b981 100%)';
                            e.currentTarget.style.boxShadow = '0 4px 12px rgba(16, 185, 129, 0.3)';
                          }
                        }}
                        onMouseLeave={(e) => {
                          if (!downloading[material.id]) {
                            e.currentTarget.style.background = 'linear-gradient(135deg, #10b981 0%, #34d399 100%)';
                            e.currentTarget.style.boxShadow = 'none';
                          }
                        }}
                      >
                        {downloading[material.id] ? (
                          <>
                            <FaSpinner style={{ animation: 'spin 1s linear infinite' }} />
                            Downloading...
                          </>
                        ) : (
                          <>
                            <FaDownload /> Download
                          </>
                        )}
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default MaterialsPage;
